racing_ui_TimeBoard.getRankText = function(rank) {
	var rankStr = rank == null ? "null" : "" + rank;
	if(rank > 10 && rank < 20) {
		return rankStr + "th";
	}
	var lastDigit = rank % 10;
	if(lastDigit == 1) {
		return rankStr + "st";
	} else if(lastDigit == 2) {
		return rankStr + "nd";
	} else if(lastDigit == 3) {
		return rankStr + "rd";
	}
	return rankStr + "th";
};
