								var p2 = 1 - 0.5 * d22;
								var m2 = 1 - d22 * d22 / 8;
								var nx2 = (p2 * _this2.axisx + dr2 * _this2.axisy) * m2;
								_this2.axisy = (p2 * _this2.axisy - dr2 * _this2.axisx) * m2;
