							if(dr4 * dr4 > 0.0001) {
								_this4.axisx = Math.sin(_this4.rot);
								_this4.axisy = Math.cos(_this4.rot);
							} else {
								var d24 = dr4 * dr4;
								var p4 = 1 - 0.5 * d24;
								var m4 = 1 - d24 * d24 / 8;
								var nx4 = (p4 * _this4.axisx + dr4 * _this4.axisy) * m4;
								_this4.axisy = (p4 * _this4.axisy - dr4 * _this4.axisx) * m4;
								_this4.axisx = nx4;
							}
							var t6 = (xx + xy) * this.b2.imass;
							this.b2.posx += gnormx * t6;
							this.b2.posy += gnormy * t6;
