								var g1y1 = 0.0;
								var t41 = s14;
								g1x1 = q01.x + qx1 * t41;
								g1y1 = q01.y + qy1 * t41;
								var g2x1 = 0.0;
								var g2y1 = 0.0;
								var t42 = s24;
								g2x1 = q01.x + qx1 * t42;
								g2y1 = q01.y + qy1 * t42;
